/* ---------- Cost Scenarios ---------- */
function costScenarios(city, mult, cd) {
  const budgetTotal = Math.round(22500 * mult / 500) * 500;
  const midTotal = Math.round(48000 * mult / 500) * 500;
  const premTotal = Math.round(95000 * mult / 500) * 500;

  const budgetBody = `${cd.cabinetSupplyChainPara.split(". ")[0]}. ${cd.countertopTrendsPara.split(". ")[0]}.`;
  const midBody = `${cd.applianceUpsellPara.split(". ")[0]}. ${cd.permitAndElectricalPara.split(". ")[0]}.`;
  const premBody = `${cd.localDesignerCulturePara.split(". ")[0]}. ${cd.historicDistrictConstraintsPara.split(". ")[0]}.`;

  function card(label, title, total, body, color) {
    return `
<div class="fp-scenario-card" style="border-top:4px solid ${color};">
<h3>${label}</h3>
<p class="fp-scenario-material">${title}</p>
<p class="fp-scenario-total">${fmtK(total)}</p>
<p class="fp-scenario-detail">${body}</p>
</div>`;
  }

  return `
<section class="section fp-section">
<h2>${city} Kitchen Remodel Project Scenarios</h2>
<div class="fp-scenario-grid">
${card("Budget", `Minor ${city} refresh`, budgetTotal, budgetBody, "#22c55e")}
${card("Mid-Range", `${city} mid-range remodel`, midTotal, midBody, "#3b82f6")}
${card("Premium", `${city} full gut renovation`, premTotal, premBody, "#8b5cf6")}
</div>
</section>`;
}

